var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"죽어! 죽으라고!!","JPN":"死んじゃえ！　死ね！!","ENG":"Die! Die!","TWN":"去死！去死吧！！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"죽어서 내 앞에서 사라져 버려!!","JPN":"死んでアタシの前から消え失せろ！！","ENG":"Get out of my face and die!","TWN":"從我眼前消失！！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"크윽......!","JPN":"くうっ……！","ENG":"Ugh!","TWN":"呃……！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"잉그리드! 괜찮아?! 지금 도와줄게!","JPN":"イングリッド！　大丈夫？　今助けます！","ENG":"Ingrid! Are you alright? I'm on my way!","TWN":"英格麗！妳沒事吧？！我來幫妳！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"난 괜찮아! 잠깐만 기다려 줘!","JPN":"私は大丈夫！　ちょっとだけ待って！","ENG":"I'm okay! Just give me a sec!","TWN":"我沒事！妳再等一下！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"뭐? 이 상황에 무슨 소릴 하는 거야!","JPN":"何？　こんな状況で何を言ってるんだ！","ENG":"Huh? What are you talking about?","TWN":"什麼？妳在說什麼呢！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"무서워하지 마, 수녀님!","JPN":"怖がらないで、シスター！","ENG":"Don't be scared, sister!","TWN":"不要害怕，修女大人！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"죽어......!","JPN":"死ね……！","ENG":"Die!","TWN":"去死……！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"나도 조금 전까지 꼭두각시 신세였으니까 알 수 있어.","JPN":"私もさっきまでは操り人形だったからわかる。","ENG":"I can tell what you're going through since I was a puppet just till now.","TWN":"剛剛我也是個傀儡，所以我知道。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"인형들끼리 연결된 실로 네 과거를 조금 엿볼 수 있었거든.","JPN":"人形同士繋がった糸で、君の過去を少し覗くことができたんだ。","ENG":"I could get a glimpse of your past through the strings that connected us together.","TWN":"我可以通過木偶之間連接的線，看到妳的過去。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"죽어! 죽으라고!","JPN":"死ね！　死ね！","ENG":"Die! Die!","TWN":"去死！去死吧！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"이유는 잘 모르겠지만...... 아무도 없는 방에 혼자 아주 오랫동안 갇혀 있었지?","JPN":"理由はよくわからないけど……\\n誰もいない部屋に一人で長い間閉じ込められてたよね？","ENG":"I don't know why... but you were locked up inside a room by yourself for a very long time, weren't you?","TWN":"雖然不知道為什麼……但妳曾在空無一人的房間裡被關了很久吧？"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_EATER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"거기 있는 동안 네가 알던 사람들은 하나 둘씩 떠나갔고.","JPN":"そこにいる間、君の知人は一人ずつ去って行った。","ENG":"And everyone you knew left one by one while you were there.","TWN":"在那期間，妳認識的人一個個都離開了妳。"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_EATER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"무서웠을 거야. 밖으로 나온 지금도 소중한 사람들이 그렇게 네 곁을 떠나 버릴까 봐.","JPN":"怖かったよね。外に出た今も、大切な人たちが\\n君のそばから離れてしまうかもしれないって。","ENG":"And you were scared that everyone around you would leave you again, even after you made it out of that room.","TWN":"妳很害怕吧？怕現在那些妳所珍惜的人也會離開妳。"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_EATER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"죽어......!","JPN":"死ね……！","ENG":"Die!","TWN":"去死……！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"거친 성격이나 말투도 애초에 사람들이랑 친해지기 싫어서 꾸미는 거잖아.","JPN":"乱暴な性格や言葉遣いも、人と仲良くなりたくなくて、そんな仮面を被ってるんだよね？","ENG":"All this tough talk and attitude is just an act, because you don't want to get close to anyone.","TWN":"粗暴的脾氣和語氣，也是為了故意不和人親近所以才裝出來的。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"혼자 남는 경험은 이미 충분하니까.","JPN":"一人ぼっちになる経験はもう十分だから。","ENG":"You don't want to lose people special to you ever again.","TWN":"因為妳不想再獨自一人了。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"죽고...... 싶지 않아.","JPN":"死に……たくない。","ENG":"I don't... want to die.","TWN":"我……不想死。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"혼자 남고 싶지 않아......","JPN":"一人ぼっちは嫌だ……","ENG":"I don't want to be left all alone...","TWN":"我不想成為一個人……"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"걱정하지 마! 우리가 같이 있어 줄게!","JPN":"大丈夫！　私たちがそばにいてあげるから！","ENG":"Don't worry! We'll stay by your side!","TWN":"不要擔心！我們會陪在妳身邊！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"오늘은 할로윈이잖아. 축제라면 다 같이 모여서 신나게 놀아야지.","JPN":"今日はハロウィンでしょう？　祭りの日は、みんなでワイワイしないと。","ENG":"It's Halloween today. We should all celebrate together.","TWN":"今天是萬聖節，慶典就應該是大家聚在一起歡樂地玩。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"잉그리드! 물러서!!","JPN":"イングリッド！　下がって！！","ENG":"Ingrid! Get back!","TWN":"英格麗！退後！！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"파이어 볼!!","JPN":"ファイヤボール！！","ENG":"Fireball!","TWN":"火焰球！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"잉그리드! 왜 안 피한 거야?!","JPN":"イングリッド！　なんで避けなかったんですか！？","ENG":"Ingrid! Why didn't you dodge?","TWN":"英格麗！妳為什麼不躲開？！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"끄응......","JPN":"ううっ……","ENG":"*Groan*","TWN":"呃……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"잘난 척 말해 놓고 혼자 불벼락 맞게 놔둘 수는 없잖아......","JPN":"偉そうなこと言った癖に、一人だけで君の魔法を受けさせるわけにはいかないでしょ……","ENG":"I couldn't let her take that alone after that fancy monologue...","TWN":"我都說了那些話，總不能讓她自己獨自承受火焰球吧……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"괜찮아! 이 정도는 하, 하나도 안 뜨겁다고......","JPN":"大丈夫！　これくらい、ぜ、全然熱くない……","ENG":"It's okay! I-I can handle this much heat...","TWN":"沒關係！這一點都，都不燙……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"질질 짜고 있으면서 말은 잘하네.","JPN":"ボロボロ泣いてるくせに口だけは達者だな。","ENG":"At least dry your tears if you're going to act tough.","TWN":"能不能先擦乾眼淚再說啊。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"이리 와, 잉그리드. 마침 화상에 잘 듣는 연고가 있거든.","JPN":"こっちにいらっしゃい、イングリッド。火傷に効く薬があるの。","ENG":"Come here, Ingrid. I've got a balm that does wonders for burns.","TWN":"過來，英格麗，我正好帶了治療燒傷的軟膏。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"그렇게 말해 놓고 또 이상한 약 시험하는 거 아니지?","JPN":"そんなこと言って、また変な薬を試したりしないよね？","ENG":"You're not just trying to test out one of your weird experiments again, are you?","TWN":"妳不會是想給我塗什麼試驗中的藥吧？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"후훗. 좋은 기회이긴 하지만 오늘은 검증된 시약만 쓸 거야.","JPN":"そうしたいのは山々だけど、今日のところは検証済みの薬だけにするわね。","ENG":"Hah hah. It would be an excellent opportunity, but I'm going to use only what's been tested already for today.","TWN":"嘿嘿，雖然是個很好的機會，但今天我只用經過驗證的藥。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"으으......","JPN":"うう……","ENG":"Ugh...","TWN":"呃呃……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"오, 수녀님. 일어났어?","JPN":"お、シスター。目が覚めた？","ENG":"Oh, hey sister. You up?","TWN":"噢，修女大人，妳醒了？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"......놔.","JPN":"……離せ！","ENG":"Let me go.","TWN":"……放開。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"응? 뭐라고?","JPN":"え？　何？","ENG":"Huh? What was that?","TWN":"嗯？妳說什麼？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"놓으라고! 이 이교도 자식아!!","JPN":"離せ！　この異教徒め！？","ENG":"Take your stinking hands off me, you dirty heretic!","TWN":"我叫妳放開！妳這個異教徒！！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"너, 너무해...... 불덩이도 같이 맞아줬는데.","JPN":"ひ、ひどい……火の玉も一緒に受けてあげたのに。","ENG":"Y-you're so mean... I even took that fireball for you.","TWN":"妳、妳太過分了……我還替妳擋下了火焰球呢。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"시끄러워. 기억 안 나.","JPN":"うるさい。思い出さない。","ENG":"Shut up, I don't remember.","TWN":"吵死了，我才不記得。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"저, 괜찮으신 거 맞죠? 혹시 이게 몇 개로 보여요?","JPN":"あの、大丈夫ですか？　これ、何個に見えますか？","ENG":"Are you sure you're alright? How many fingers am I holding up?","TWN":"妳，沒事吧？妳看看這是幾？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"누굴 바보로 알아? 멀쩡하니까 저리 치워.","JPN":"バカにしないで。全然平気だから、あっち行け。","ENG":"You think I'm stupid? Get that out of my face. I'm fine.","TWN":"妳以為我傻了？我清醒的很，把妳的手拿開。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"헤헷. 그래도 다행이네. 저주에서 풀려나서.","JPN":"へへっ。でも良かった。呪いから解放されて。","ENG":"Heh, at least we managed to break the curse.","TWN":"嘿嘿，太好了。終於從詛咒解脫了。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"혹시라도 유나가 만든 불꽃이 안 통하면 어쩌나 걱정했거든.","JPN":"万が一、ユナの炎が効かなかったらどうしようって心配してたよ。","ENG":"I was worried that Yuna's flames might not work for a second there.","TWN":"我還擔心萬一尤娜的火焰球不管用該怎麼辦呢。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"시끄러워. 너야말로 남의 개인사 갖고 쓸데없는 소리 하지 마.","JPN":"うるさい。あんたも人のプライベートを言いふらすな。","ENG":"Shut up. And don't go telling anyone about my personal life.","TWN":"閉嘴，妳不要把我的私事到處說。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"내 귀에 들어오면 정말 화형대에 올려버릴 테니까!","JPN":"もしアタシの耳に入ったら本当に火刑台へ送るからな！","ENG":"If I hear it from anyone else, I'm going to burn you at the stake! Literally!","TWN":"如果被我聽到了，我就親手把妳送到火刑台！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"걱정 마시라. 우리 카페엔 고객 사생활을 철저히 보호한다는 규정도 있거든.","JPN":"心配しないで。うちのカフェにはお客さんの\\nプライベートは徹底的に守るという規定があるよ。","ENG":"Don't worry. Our cafe has a strict privacy policy.","TWN":"別擔心，我們咖啡店有嚴格保護顧客隱私的規定。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"그래서, 본 건 그게 다야?","JPN":"それで、見たのはそれだけか？","ENG":"So... Is that all you saw?","TWN":"所以，妳看到的就只有那些？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"응? 어, 그, 그렇긴 한데......","JPN":"え？　えっと、そうだけど……","ENG":"Huh? Y-yeah, I think...","TWN":"嗯？是，是這樣沒錯……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"운이 좋구만. 조금만 더 많이 들여다 봤으면 뒤통수 한 대 쳐서 기억을 날려 버렸을 텐데.","JPN":"運が良かったな。もう少し覗いてたら後頭部を殴って\\n記憶を消してやるつもりだったけど。","ENG":"You got lucky. If you peeked any further, I was going to whack you on the head to erase your memory.","TWN":"算妳走運。如果妳看到別的，我肯定給妳一巴掌，讓妳通通忘掉。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"야, 야. 왜 그래. 살벌하게.","JPN":"ね、ねぇ。どうしたの。怖いよ。","ENG":"Come on, no need to be so scary now.","TWN":"喂，喂，幹嘛這麼嚇人。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그럼 이걸로 남은 사람은 한 명뿐이네.","JPN":"さて、これであと一人か。","ENG":"So that leaves us with just one more to go.","TWN":"現在就只剩下一個人了。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"어서 가자. 주인이 결계를 완전히 파괴하기 전에 찾아야 돼.","JPN":"さっさと行こう。人形の持ち主が結界を破壊しきる前に取り戻さなければならない。","ENG":"Let's get going. We have to find her before the Puppet Master breaks the barrier completely.","TWN":"快走吧，趁木偶之主還沒有完全破壞結界之前。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};